class LFUCache {
    Map<Integer, Integer> map;
    int capacity;

    LFUCache(int capacity) {
        this.capacity = capacity;
        map = new HashMap<>();
    }

    int get(int key) {
        Integer value = map.get(key);
        if (value == null) {
            map.put(key, capacity);
            value = map.get(key);
        }
        return value;
    }

    void put(int key, int value) {
        if (map.containsKey(key)) {
            map.put(key, value);
        } else {
            map.put(key, capacity);
            map.put(key, value);
        }
    }
}
```

